const total = catalog.length;
const readKey = 'slmpDeviceMatrixReadIndex';
const writeKey = 'slmpDeviceMatrixWriteIndex';
const resultsKey = 'slmpDeviceMatrixResults';
const pendingKey = 'slmpDeviceMatrixPendingById';
const sessionKey = 'slmpDeviceMatrixSessionId';
const logPathKey = 'slmpDeviceMatrixLogPath';
const timeoutKey = 'slmpDeviceMatrixTimeoutMs';
const totalKey = 'slmpDeviceMatrixTotalCatalog';
const action = String(msg.mode || 'catalog');

flow.set(totalKey, total);
flow.set('slmpDeviceMatrixCatalog', catalog);
if (!flow.get(timeoutKey)) {
    flow.set(timeoutKey, 5000);
}

function makeSessionId() {
    return new Date().toISOString().replace(/[:.]/g, '-');
}

function ensureSessionId(reset) {
    let sessionId = flow.get(sessionKey);
    if (reset || !sessionId) {
        sessionId = makeSessionId();
        flow.set(sessionKey, sessionId);
    }
    return sessionId;
}

function ensureLogPath(sessionId, reset) {
    let logPath = flow.get(logPathKey);
    if (reset || !logPath) {
        logPath = 'logs/slmp-device-matrix-' + sessionId + '.jsonl';
        flow.set(logPathKey, logPath);
    }
    return logPath;
}

function getPendingMap() {
    return Object.assign({}, flow.get(pendingKey) || {});
}

function getResults() {
    return Array.from(flow.get(resultsKey) || []);
}

function buildSummary() {
    const results = getResults();
    const pending = getPendingMap();
    const summary = {
        kind: 'summary',
        sessionId: ensureSessionId(false),
        logPath: ensureLogPath(ensureSessionId(false), false),
        totalCatalog: total,
        completed: results.length,
        ok: 0,
        ng: 0,
        mismatch: 0,
        timeout: 0,
        pending: Object.keys(pending).length,
        pendingIds: Object.keys(pending)
    };
    for (const entry of results) {
        if (entry.status === 'OK') {
            summary.ok += 1;
        } else {
            summary.ng += 1;
            if (entry.status === 'MISMATCH') {
                summary.mismatch += 1;
            }
            if (entry.status === 'TIMEOUT') {
                summary.timeout += 1;
            }
        }
    }
    return summary;
}

function registerPending(kind, index, entry) {
    const sessionId = ensureSessionId(false);
    const logPath = ensureLogPath(sessionId, false);
    const now = new Date().toISOString();
    const requestId = kind + '-' + entry.code + '-' + String(index + 1) + '-' + String(Date.now());
    const pending = getPendingMap();
    const record = {
        kind: 'result',
        requestId: requestId,
        sessionId: sessionId,
        logPath: logPath,
        operation: kind,
        action: kind === 'write' ? 'write-readback' : 'read',
        deviceCode: entry.code,
        address: entry.address,
        target: entry.target || null,
        note: entry.note,
        sequence: {
            index: index + 1,
            total: total
        },
        status: 'PENDING',
        phase: kind === 'write' ? 'WRITE_PENDING' : 'READ_PENDING',
        ok: null,
        expectedValue: kind === 'write' ? entry.value : null,
        writeValue: kind === 'write' ? entry.value : null,
        writeStatus: kind === 'write' ? 'PENDING' : 'SKIPPED',
        readValue: null,
        readStatus: 'PENDING',
        readbackStatus: kind === 'write' ? 'PENDING' : 'SKIPPED',
        error: null,
        startedAt: now,
        updatedAt: now,
        finishedAt: null
    };
    pending[requestId] = record;
    flow.set(pendingKey, pending);
    return record;
}

if (action === 'reset') {
    const sessionId = ensureSessionId(true);
    const logPath = ensureLogPath(sessionId, true);
    flow.set(readKey, 0);
    flow.set(writeKey, 0);
    flow.set(resultsKey, []);
    flow.set(pendingKey, {});
    return [null, null, {
        payload: {
            kind: 'reset',
            sessionId: sessionId,
            logPath: logPath,
            totalCatalog: total,
            timeoutMs: flow.get(timeoutKey),
