const timeoutMs = Number(flow.get('slmpDeviceMatrixTimeoutMs') || 5000);
const pending = Object.assign({}, flow.get(pendingKey) || {});
const results = Array.from(flow.get(resultsKey) || []);
const total = Number(flow.get(totalKey) || 0);
const nowMs = Date.now();
const timedOut = [];

function buildSummary() {
    const summary = {
        kind: 'summary',
        sessionId: flow.get(sessionKey) || null,
        logPath: flow.get(logPathKey) || null,
        totalCatalog: total,
