    };
    for (const entry of results) {
        if (entry.status === 'OK') {
            summary.ok += 1;
        } else {
            summary.ng += 1;
            if (entry.status === 'MISMATCH') {
                summary.mismatch += 1;
            }
            if (entry.status === 'TIMEOUT') {
                summary.timeout += 1;
            }
        }
    }
    return summary;
}

for (const requestId of Object.keys(pending)) {
    const record = pending[requestId];
    const started = Date.parse(record.updatedAt || record.startedAt || '');
    if (!Number.isFinite(started)) {
        continue;
    }
    if ((nowMs - started) < timeoutMs) {
        continue;
    }

    const finishedAt = new Date().toISOString();
    const timedOutRecord = Object.assign({}, record, {
        status: 'TIMEOUT',
        phase: 'DONE',
        ok: false,
        error: 'No completion within ' + String(timeoutMs) + ' ms',
        updatedAt: finishedAt,
        finishedAt: finishedAt
    });

    if (timedOutRecord.operation === 'write') {
        if (timedOutRecord.writeStatus === 'PENDING') {
            timedOutRecord.writeStatus = 'TIMEOUT';
            timedOutRecord.readStatus = 'SKIPPED';
            timedOutRecord.readbackStatus = 'SKIPPED';
        } else {
            timedOutRecord.readStatus = 'TIMEOUT';
            timedOutRecord.readbackStatus = 'TIMEOUT';
        }
    } else {
        timedOutRecord.writeStatus = 'SKIPPED';
        timedOutRecord.readStatus = 'TIMEOUT';
        timedOutRecord.readbackStatus = 'SKIPPED';
    }

    delete pending[requestId];
    results.push(timedOutRecord);
    timedOut.push(timedOutRecord);
}

if (timedOut.length === 0) {
    return null;
}

flow.set(pendingKey, pending);
flow.set(resultsKey, results);

return [
    timedOut.map(function (entry) { return { payload: entry }; }),
    [{ payload: results }],
    [{ payload: buildSummary() }],
